func (m seasonDriverMods) WithParentsCascading() SeasonDriverMod {
	return SeasonDriverModFunc(func(ctx context.Context, o *SeasonDriverTemplate) {
		if isDone, _ := seasonDriverWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = seasonDriverWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewCarModelWithContext(ctx, CarModelMods.WithParentsCascading())
			m.WithCarModel(related).Apply(ctx, o)
		}
		{

			related := o.f.NewDriverWithContext(ctx, DriverMods.WithParentsCascading())
			m.WithDriver(related).Apply(ctx, o)
		}
		{

			related := o.f.NewSeasonWithContext(ctx, SeasonMods.WithParentsCascading())
			m.WithSeason(related).Apply(ctx, o)
		}
	})
}

